() => {
  const gallery = document.querySelector('[data-widget_type*="gallery"]');
  if (!gallery) return 'no gallery';
  let el = gallery;
  const chain = [];
  while (el && el !== document.body) {
    const style = getComputedStyle(el);
    const rect = el.getBoundingClientRect();
    chain.push({
      tag: el.tagName,
      class: el.className.split(' ').filter(c => c.startsWith('elementor-element-') || c.startsWith('e-') || c === 'elementor-widget').join(' '),
      dataId: el.dataset.id || '',
      width: Math.round(rect.width),
      maxWidth: style.maxWidth,
      cssWidth: style.width,
      display: style.display,
      flexBasis: style.flexBasis
    });
    el = el.parentElement;
  }
  return chain;
}

() => {
  const gallery = document.querySelector('[data-widget_type*="gallery"]');
  if (!gallery) return 'no gallery';
  const container = gallery.querySelector('.e-gallery-items, .elementor-gallery__container, .gallery');
  const items = gallery.querySelectorAll('.e-gallery-item, .elementor-gallery-item');
  const imgs = gallery.querySelectorAll('img');

  const containerRect = container ? container.getBoundingClientRect() : null;
  const galleryRect = gallery.getBoundingClientRect();

  return {
    galleryWidth: Math.round(galleryRect.width),
    galleryHeight: Math.round(galleryRect.height),
    containerWidth: containerRect ? Math.round(containerRect.width) : null,
    containerHeight: containerRect ? Math.round(containerRect.height) : null,
    containerClass: container ? container.className : 'not found',
    itemCount: items.length,
    imgCount: imgs.length,
    firstItemWidth: items[0] ? Math.round(items[0].getBoundingClientRect().width) : null,
    firstItemHeight: items[0] ? Math.round(items[0].getBoundingClientRect().height) : null,
    gallerySettings: gallery.dataset
  };
}

() => {
  const items = document.querySelectorAll('.e-gallery-item');
  const results = [];
  items.forEach((item, i) => {
    const bg = item.querySelector('.e-gallery-image');
    const rect = item.getBoundingClientRect();
    const style = bg ? getComputedStyle(bg) : {};
    results.push({
      index: i,
      width: Math.round(rect.width),
      height: Math.round(rect.height),
      aspectRatio: (rect.width / rect.height).toFixed(2),
      bgSize: style.backgroundSize || '',
      bgImage: (style.backgroundImage || '').substring(0, 80)
    });
  });
  return results;
}

