/**
 * ============================================================================
 * ELEMENTOR GALLERY: Override ideal_row_height for page "Linha do Tempo"
 * ============================================================================
 *
 * The Elementor Pro gallery widget "justified" layout uses ideal_row_height
 * to calculate item widths. With portrait images (9:16), the default 200px
 * row height makes items too narrow to fill the container.
 *
 * Approach: inline JS that patches the gallery widget's data-settings and
 * triggers re-layout after Elementor initializes. This is necessary because
 * Elementor caches parsed settings internally (private properties) and
 * ignores values set via set_settings() in before_render hooks.
 *
 * Page ID 26769 = /cultura/linha-do-tempo/ (blog 2)
 *
 * @since 2.2.3
 */
add_action('wp_footer', function () {
    if ((int) get_the_ID() !== 26769) {
        return;
    }
    ?>
    <script>
    (function(){
        var g = document.querySelector('[data-widget_type="gallery.default"]');
        if (!g) return;
        var s = g.getAttribute('data-settings');
        if (!s || s.indexOf('"gallery_layout":"justified"') === -1) return;
        s = s.replace(
            '"ideal_row_height":{"unit":"px","size":200,"sizes":[]}',
            '"ideal_row_height":{"unit":"px","size":350,"sizes":[]}'
        );
        g.setAttribute('data-settings', s);
        /* Trigger Elementor gallery re-init */
        var evt = new Event('resize');
        window.dispatchEvent(evt);
    })();
    </script>
    <?php
}, 99);

