() => {
  const gallery = document.querySelector('[data-widget_type="gallery.default"]');
  if (!gallery) return 'no gallery';
  gallery.scrollIntoView({block: 'center'});
  const settings = JSON.parse(gallery.getAttribute('data-settings') || '{}');
  const items = document.querySelectorAll('.e-gallery-item');
  return {
    idealRowHeight: settings.ideal_row_height,
    galleryWidth: Math.round(gallery.getBoundingClientRect().width),
    galleryHeight: Math.round(gallery.getBoundingClientRect().height),
    itemWidth: items[0] ? Math.round(items[0].getBoundingClientRect().width) : null,
    itemHeight: items[0] ? Math.round(items[0].getBoundingClientRect().height) : null,
    itemCount: items.length
  };
}

