1	<?php
2	/**
3	 * Plugin Name:  Gallery Attachment Title Fix
4	 * Description:  In blog 2 context, falls back to blog 1's attachment title when
5	 *               get_the_title() is called for an ID that doesn't exist or is not
6	 *               an attachment in blog 2.
7	 *               Covers the path where get_the_title() is called directly (e.g.
8	 *               themes or plugins iterating a gallery loop), which is NOT covered
9	 *               by the warm_cache pre-population in bit-crossblog-attachment-fix.php
10	 *               (that covers get_lightbox_image_attributes() via object cache, but
11	 *               not direct get_the_title() calls outside widget render context).
12	 *               Practical use: Elementor gallery lightbox captions on /cultura/galeria/.
13	 * Version:      1.0.1
14	 * Author:       Bureau IT
15	 * Network:      true
16	 */
17	
18	if ( ! defined( 'ABSPATH' ) ) {
19		exit;
20	}
21	
22	add_filter( 'the_title', function ( $title, $post_id ) {
23		// Only apply in blog 2 context
24		if ( get_current_blog_id() !== 2 ) {
25			return $title;
26		}
27	
28		$post = get_post( $post_id );
29	
30		// Only intervene when post doesn't exist in blog 2 at all
31		if ( $post ) {
32			return $title;
33		}
34	
35		// Cache blog 1 attachment title lookups to avoid repeated switch_to_blog() calls
36		static $cache = [];
37	
38		if ( ! array_key_exists( $post_id, $cache ) ) {
39			switch_to_blog( 1 );
40			$b1 = get_post( $post_id );
41			restore_current_blog();
42			$cache[ $post_id ] = ( $b1 && $b1->post_type === 'attachment' )
43				? $b1->post_title
44				: null;
45		}
46	
47		return $cache[ $post_id ] !== null ? $cache[ $post_id ] : $title;
48	}, 10, 2 );
