}


/* ==========================================================================
   7. Elementor Widget — Visualização de Eventos (Events View)
   Libera controles de cor do painel Elementor para a list view.
   O TEC Pro seta CSS vars em elementos filhos via {{WRAPPER}}, mas o CSS
   nativo do TEC lê de :root. Estes overrides fazem o color herdar do
   parent (onde o Elementor injeta a variável) com fallback para o valor
   original do TEC.
   ========================================================================== */

/* Título do evento */
.tribe-events .tribe-events-calendar-list__event-title {
    color: var(--tec-color-text-events-title, var(--tec-color-text-event-title-list));
